population_density = {
    'area1': 1000, 
    'area2': 2500, 
    'area3': 4000,
}

# Step 2: Determine the optimal amount of toxic chemicals to release based on population density.
def calculate_optimal_toxic_release(population_density):
    # Initialize a dictionary to store the optimal toxic amounts for each area.
    optimal_toxic_amounts = {}

    # Iterate through each area and calculate the optimal amount of toxic chemicals.
    for area, density in population_density.items():
        if density <= 1000:
            optimal_toxic_amounts[area] = 0.05 * density
        elif density <= 3000:
            optimal_toxic_amounts[area] = 0.1 * density
        else:
            optimal_toxic_amounts[area] = 0.
